('1543774226016276481', '2022-07-04 01:50:32', 'rezakaisar3', 'AFC masih kesulitan mendapatkan tuan rumah baru untuk gelaran Piala Asia 2023 mendatang. AFC perpanjang pengajuan tuan rumah sampai dengan 15 Juli mendatang.\n\nAlasannya, karena imbas invasi militer Rusia ke Ukraina', 'afc masih kesulitan mendapatkan tuan rumah baru untuk gelaran piala asia mendatang afc perpanjang pengajuan tuan rumah s ai dengan juli mendatang alasannya karena imbas invasi militer rusia ke ukraina', 'duplikat', 'tidak', ''),
('1543774812790992896', '2022-07-04 01:52:51', 'rezakaisar3', '@rizkkkisub @Indostransfer AFC masih kesulitan mendapatkan tuan rumah baru untuk gelaran Piala Asia 2023 mendatang. AFC perpanjang pengajuan tuan rumah sampai dengan 15 Juli mendatang.\n\nAlasannya, karena imbas invasi militer Rusia ke Ukraina', 'afc masih kesulitan mendapatkan tuan rumah baru untuk gelaran piala asia mendatang afc perpanjang pengajuan tuan rumah s ai dengan juli mendatang alasannya karena imbas invasi militer rusia ke ukraina', 'duplikat', 'tidak', ''),
('1543776239470514176', '2022-07-04 01:58:32', 'smogaawet', '@mujahidabqori Coba lu pikir .. org no 1 di negri kita, bikin hoax trkait 2 negara yg lg konflik.. fatal ga tuh, lu kan punya otak, pikir dah baik2.. liat efeknya skrng rusia makin gencar invasi ke ukraina', 'coba lu pikir org no di negri kita bikin hoax trkait negara yg lg konflik fatal ga tuh lu kan punya otak pikir dah baik liat efeknya skrng rusia makin gencar invasi ke ukraina', 'umum', 'tidak', ''),
('1543811464401547264', '2022-07-04 04:18:30', 'mediaindonesia', '\"IOC akan melipattigakan dana yang telah kami siapkan sejak invasi Rusia ke Ukraina dari US$2,5 juta menjadi US$7,5 juta.\"  https://t.co/xXcjUfT0jp', 'ioc akan melipattigakan dana yang telah kami siapkan sejak invasi rusia ke ukraina dari us juta menjadi us juta', 'umum', 'tidak', ''),
('1543813113824575488', '2022-07-04 04:25:03', 'ari_ap', '@amirk Oh ok kalau ini bener objective-nya, artinya ukuran sukses adalah kalau Rusia akhiri invasi', 'oh ok kalau ini bener objective nya artinya ukuran sukses adalah kalau rusia akhiri invasi', 'umum', 'tidak', ''),
('1543834378962288641', '2022-07-04 05:49:33', 'kompascom', 'Eropa kini mengalami lonjakan harga energi yang salah satunya dipicu oleh invasi Rusia ke Ukraina, bagaimana pemerintahnya menangani masalah ini? https://t.co/cmFsorjzYs', 'eropa kini mengalami lonjakan harga energi yang salah satunya dipicu oleh invasi rusia ke ukraina bagaimana pemerintahnya menangani masalah ini', 'umum', 'tidak', ''),
('1543837010405642241', '2022-07-04 06:00:01', 'TirtoID', 'Sejak abad ke-13 sampai era Perang Dunia II, Rusia pernah jadi sasaran invasi bangsa Mongol, Polandia, Swedia, Prancis, dan Nazi Jerman.\n\nhttps://t.co/9hBEeo4yGg https://t.co/dMc6QRq8y9', 'sejak abad ke s ai era perang dunia ii rusia pernah jadi sasaran invasi bangsa mongol polandia swedia prancis dan nazi', 'umum', 'tidak', ''),
('1543839144131997699', '2022-07-04 06:08:29', 'SekuritasBahana', 'Associate Director Pilarmas Investindo Sekuritas, Maximilianus Nico Demus mengatakan kalau IHSG masih sangat dilematis dengan masalah seperti sebelumnya yaitu inflasi, kenaikan tingkat suku bunga, resesi, perlambatan ekonomi, dan juga invasi Rusia-Ukraina.', 'associate director pilarmas investindo sekuritas maximilianus nico demus mengatakan kalau ihsg masih sangat dilematis dengan masalah seperti sebelumnya yaitu inflasi kenaikan tingkat suku bunga resesi perlambatan ekonomi dan juga invasi rusia ukraina', 'umum', 'tidak', ''),
('1543869456862310400', '2022-07-04 08:08:56', 'rezakaisar3', '@SusahSembuh_YK AFC masih kesulitan mendapatkan tuan rumah baru untuk gelaran Piala Asia 2023 mendatang. AFC perpanjang pengajuan tuan rumah sampai dengan 15 Juli mendatang.\n\nAlasannya, karena imbas invasi militer Rusia ke Ukraina', 'afc masih kesulitan mendapatkan tuan rumah baru untuk gelaran piala asia mendatang afc perpanjang pengajuan tuan rumah s ai dengan juli mendatang alasannya karena imbas invasi militer rusia ke ukraina', 'duplikat', 'tidak', ''),
('1543873279055646721', '2022-07-04 08:24:08', 'IDNTimes', 'Serbia ogah terlibat dalam invasi Rusia di Ukraina https://t.co/i3CsEQ4s4X', 'serbia ogah terlibat dalam invasi rusia di ukraina', 'umum', 'tidak', ''),
('1543887074306142208', '2022-07-04 09:18:57', 'Burakos7', '@dinopattidjalal @msaid_didu Klu tdk salah presiden &amp; menhan Ukraine sdh pernah sikapi isu invasi rusia tdk akan diselesaikan dlm perundingan damai. Tpi, bgimana menangkan perang dari penjajah Rusia. Spt sikap para pejuang kemerdekaan RI...merdeka atau mati!!!', 'klu tdk salah presiden menhan ukraine sdh pernah sikapi isu invasi rusia tdk akan diselesaikan dlm perundingan damai tpi bgimana menangkan perang dari penjajah rusia spt sikap para pejuang kemerdekaan ri merdeka atau mati', 'umum', 'tidak', '');
INSERT INTO `dataset` (`id`, `tanggal`, `username`, `isi`, `pra`, `jenis`, `status`, `sentistrength`) VALUES
('1543901665509531649', '2022-07-04 10:16:56', 'VeritasArdentur', 'Yg dilakukan ukraina sekarang, adalah memperlemah rusia, supaya nggak invasi ke negara lain. Which putin never said he intended to do anyway.\n\nJadi untuk kepentingan NATO, dia bersedia mengorbankan rakyat ukraina sebagai canon fodder.\n\nToh dia dan apparatchiknya dapat $9B/bln', 'yg dilakukan ukraina sekarang adalah memperlemah rusia supaya nggak invasi ke negara lain which putin never said he intended to do anyway jadi untuk kepentingan nato dia bersedia mengorbankan rakyat ukraina sebagai canon fodder toh dia dan apparatchiknya dapat b bln', 'umum', 'pakai', '{\'classified_text\': \'yg dilakukan ukraina sekarang adalah memperlemah rusia supaya nggak invasi ke negara lain which putin never said he intended to do anyway jadi untuk kepentingan nato dia bersedia mengorbankan rakyat ukraina sebagai canon fodder toh dia dan apparatchiknya dapat b bln\', \'tweet_text\': \' yg dilakukan ukraina sekarang adalah memperlemah rusia supaya nggak invasi ke negara lain which putin never said he intended to do anyway jadi untuk kepentingan nato dia bersedia mengorbankan rakyat ukraina sebagai canon fodder toh dia dan apparatchiknya dapat b bln\', \'sentence_score\': [\'yg dilakukan ukraina sekarang adalah memperlemah rusia supaya nggak invasi ke negara lain which putin never said he intended to do anyway jadi untuk kepentingan nato dia bersedia mengorbankan rakyat ukraina sebagai canon fodder toh dia dan apparatchiknya dapat b bln\'], \'max_positive\': 1, \'max_negative\': -1, \'kelas\': \'neutral\'}'),
('1543906933983174657', '2022-07-04 10:37:52', 'AgusSet92266113', 'Borok dan menjijikan aku ingat nian pele..https://t.co/zxck7zZPCP\n\nPele mengutuk invasi yang dilancarkan Presiden Rusia, Vladimir Putin. Legenda sepakbola Brasil itu meminta perang di Ukraina dihentikan.', 'borok dan menjijikan aku ingat nian mengutuk invasi yang dilancarkan presiden rusia vladimir putin legenda sepakbola brasil itu meminta perang di ukraina dihentikan', 'umum', 'tidak', ''),
('1543950287244644354', '2022-07-04 13:30:08', 'cekfaktacom', 'Faktanya, bukan demo yang ditujukan kepada Jokowi. Demo tersebut ditujukan untuk menuntut para pemimpin negara anggota G7 untuk berkomitmen dalam mengatasi krisis dunia berupa invasi Rusia ke Ukraina, perubahan iklim, serta krisis energi dan makanan.', 'faktanya bukan demo yang ditujukan kepada jokowi demo tersebut ditujukan untuk menuntut para pemimpin negara anggota g untuk berkomitmen dalam mengatasi krisis dunia berupa invasi rusia ke ukraina perubahan iklim serta krisis energi dan makanan', 'umum', 'tidak', ''),
('1543958445329682433', '2022-07-04 14:02:33', 'mbhfur', 'Bargain apa yg dimiliki Indonesia untuk membuat Rusia berpikir ulang soal invasi ke Ukraina?gak ada!!!\n\nini bukan era USSRvsUS dimana negara dunia ketiga bisa memainkan peran lebih sebab ada usaha untuk rebutan pengaruh diantara negara dunia ketiga', 'bargain apa yg dimiliki indonesia untuk membuat rusia berpikir ulang soal invasi ke ukraina gak ada ini bukan era ussrvsus dimana negara dunia ketiga bisa memainkan peran lebih sebab ada usaha untuk rebutan pengaruh diantara negara dunia ketiga', 'umum', 'tidak', ''),
('1544013577152917504', '2022-07-04 17:41:37', 'radixwp', 'Politik luar negeri Indonesia sering enggak banget.\n\nJaga jarak dg Israel saat negara2 Arab makin banyak buka hubungan diplomatik dg Israel.\n\nKatanya kemerdekaan hak segala bangsa, tapi netral wkt Rusia invasi Ukraina.\n\nIkut kecam Aung San Suu Kyi di Myanmar hanya demi Rohingya.', 'politik luar negeri indonesia sering enggak banget jaga jarak dg israel saat negara arab makin banyak buka hubungan diplomatik dg israel katanya kemerdekaan hak segala bangsa tapi netral wkt rusia invasi ukraina ikut kecam aung san suu kyi di myanmar hanya demi rohingya', 'umum', 'pakai', '{\'classified_text\': \'politik luar negeri indonesia sering enggak banget jaga jarak dg israel saat negara arab makin banyak buka hubungan diplomatik dg israel katanya kemerdekaan hak segala bangsa tapi netral wkt rusia invasi ukraina ikut kecam aung san suu kyi di myanmar hanya demi rohingya\', \'tweet_text\': \' politik luar negeri indonesia sering enggak banget jaga jarak dg israel saat negara arab makin banyak buka hubungan diplomatik dg israel katanya kemerdekaan hak segala bangsa tapi netral wkt rusia invasi ukraina ikut kecam aung san suu kyi di myanmar hanya demi rohingya\', \'sentence_score\': [\'politik luar negeri indonesia sering enggak banget jaga jarak dg israel saat negara arab makin banyak buka hubungan diplomatik dg israel katanya kemerdekaan hak segala bangsa tapi netral wkt rusia invasi ukraina ikut kecam aung san suu kyi di myanmar hanya demi rohingya\'], \'max_positive\': 1, \'max_negative\': -1, \'kelas\': \'neutral\'}'),
('1544097061179514880', '2022-07-04 23:13:21', 'Rumi03990116', 'Sanksi berupa embargo minyak untuk Rusia lantaran perang Rusia-Ukrania justru membuat sejumlah negara Eropa terancam krisis energi.  Invasi Rusia ke Ukraina telah menyebabkan kenaikan tajam berbagai harga komoditas. Bagaimanakah Islam memandang hal ini? \nhttps://t.co/0BstVso3AP https://t.co/a6E61L1vmV', 'sanksi berupa embargo minyak untuk rusia lantaran perang rusia ukrania justru membuat sejumlah negara eropa terancam krisis energi invasi rusia ke ukraina telah menyebabkan kenaikan tajam berbagai harga komoditas bagaimanakah islam memandang hal ini', 'umum', 'tidak', ''),
('1544099668040503296', '2022-07-04 23:23:43', 'indrywulanpert1', 'Serba-serbi MMC- Invasi Rusia ke Ukraina telah menyebabkan kenaikan tajam berbagai harga komoditas. lalu agaimanakah Islam memandang hal ini?\nKrisis energi\nKonflik kepentingan Rusia\n\n#Islamkaffah\nhttps://t.co/DDlhNRSwhz', 'serba serbi mmc invasi rusia ke ukraina telah menyebabkan kenaikan tajam berbagai harga komoditas lalu agaimanakah islam memandang hal ini krisis energi konflik kepentingan', 'umum', 'tidak', ''),
('1544102593982386176', '2022-07-04 23:35:21', 'DayaRahman01', 'Invasi Rusia ke Ukraina berdampak krisis energi di negeri2 lain.\nAda yang ngambil untuk juga dalam konflik ini...\nHmm, kalau dalam Islam bagaimana yah...?\n\nDibahas dalam artikel #serbaserbimmc pagi ini\n#krisisenergi\n#konflikkepentinganrusia \n\nhttps://t.co/zoZxnDm6Wz', 'invasi rusia ke ukraina berd ak krisis energi di negeri lain ada yang ngambil untuk juga dalam konflik ini hmm kalau dalam islam bagaimana yah dibahas dalam artikel pagi', 'umum', 'tidak', ''),
('1544102784454492161', '2022-07-04 23:36:06', 'AisyahAin14', 'Konflik Kepentingan Rusia Tak Dihentikan, Meski Dunia Teriak Krisis Energi? | Serba-serbi MMC\n\nInvasi Rusia ke Ukraina tlah menyebabkan kenaikan tajam berbagai harga komoditas.bagaimana pandangan Islam?\n\nhttps://t.co/s8wZEPZAfh https://t.co/rA0V6Prpnv', 'konflik kepentingan rusia tak dihentikan meski dunia teriak krisis energi | serba serbi mmc invasi rusia ke ukraina tlah menyebabkan kenaikan tajam berbagai harga komoditas bagaimana pandangan', 'umum', 'tidak', ''),
