('1550463875644268544', '2022-07-22 12:52:48', 'AliMudin328', 'Namun, beberapa klub asal Rusia yang bertanding di Liga Champions, Europa League dan Europa Conference League juga tidak boleh bertanding karena invasi tersebut.', 'namun beberapa klub asal rusia yang bertanding di liga ch ions europa league dan europa conference league juga tidak boleh bertanding karena invasi tersebut', 'umum', 'tidak', ''),
('1550480674640973826', '2022-07-22 13:59:34', 'raflyraihandy', '@medioclubID Keterlibatan Belarus dalam Operasi Militer Khusus (atau invasi) Rusia di Ukraina justru lebih susah dibuktikan dibanding keterlibatan Rusia, karena hingga saat ini Belarus pun tidak menurunkan satu pasukan pun ke wilayah konflik', 'keterlibatan belarus dalam operasi militer khusus atau invasi rusia di ukraina justru lebih susah dibuktikan dibanding keterlibatan rusia karena hingga saat ini belarus pun tidak menurunkan satu pasukan pun ke wilayah konflik', 'umum', 'tidak', ''),
