('1554010337963302912', '2022-08-01 07:45:11', '1011mgtradio', 'Presiden Ukraina Volodymyr Zelensky khawatir panen gandum dan biji-bijian dari negaranya turun setengah dari jumlah normal pada tahun ini karena invasi Rusia.\nSumber : CNN News\n#MGTRADIO #MGTPlay https://t.co/lJsUmWXczq', 'presiden ukraina volodymyr zelensky khawatir panen gandum dan biji bijian dari negaranya turun setengah dari jumlah normal pada tahun ini karena invasi rusia sumber cnn', 'umum', 'pakai', '{\'classified_text\': \'presiden ukraina volodymyr zelensky khawatir panen gandum dan biji bijian dari negaranya turun [-4] setengah dari jumlah normal [-1] pada tahun ini karena invasi rusia sumber cnn\', \'tweet_text\': \' presiden ukraina volodymyr zelensky khawatir panen gandum dan biji bijian dari negaranya turun setengah dari jumlah normal pada tahun ini karena invasi rusia sumber cnn\', \'sentence_score\': [\'presiden ukraina volodymyr zelensky khawatir panen gandum dan biji bijian dari negaranya turun [-4] setengah dari jumlah normal [-1] pada tahun ini karena invasi rusia sumber cnn\'], \'max_positive\': 1, \'max_negative\': -4, \'kelas\': \'negative\'}'),
('1554015569611194368', '2022-08-01 08:05:58', 'Kingdarius102', '@SisiwittFrida Berbeda pendapat kita ya, saya nyatakan bahwa perang dgn invasi itu ada sampai saat ini.\nContoh ;\nPerang Iraq - Iran, Iraq menginvasi Kuwait.\nKemudian Iraq di serang Amerika.\nSekarang Rusia menyerang Ukraina, diserang dgn senjata lo. Jadi itu disebut perang, invasi militer.', 'berbeda pendapat kita ya saya nyatakan bahwa perang dgn invasi itu ada s ai saat ini contoh perang iraq iran iraq menginvasi kuwait kemudian iraq di serang amerika sekarang rusia menyerang ukraina diserang dgn senjata lo jadi itu disebut perang invasi militer', 'umum', 'tidak', '');
