('1590304949527011329', '2022-11-09 11:27:01', 'gijnIndonesia', '?? Tim @OCCRP merilis berita interaktif menggunakan obrolan Telegram penduduk Block 17 di Bucha, Ukraina, tentang kehidupan mereka di bawah pengepungan selama invasi Rusia.\n\nBagaimana mereka melakukannya? https://t.co/zSHON3ztan', 'tim merilis berita interaktif menggunakan obrolan telegram penduduk block di bucha ukraina tentang kehidupan mereka di bawah pengepungan selama invasi rusia bagaimana mereka melakukannya', 'umum', 'pakai', '{\'classified_text\': \'tim merilis berita interaktif menggunakan obrolan telegram penduduk block di bucha ukraina tentang kehidupan mereka di bawah [-1] pengepungan [-4] selama invasi rusia bagaimana mereka melakukannya\', \'tweet_text\': \' tim merilis berita interaktif menggunakan obrolan telegram penduduk block di bucha ukraina tentang kehidupan mereka di bawah pengepungan selama invasi rusia bagaimana mereka melakukannya\', \'sentence_score\': [\'tim merilis berita interaktif menggunakan obrolan telegram penduduk block di bucha ukraina tentang kehidupan mereka di bawah [-1] pengepungan [-4] selama invasi rusia bagaimana mereka melakukannya\'], \'max_positive\': 1, \'max_negative\': -1, \'kelas\': \'neutral\'}'),
