('1619523433636986880', '2023-01-29 02:30:50', 'SpongeBiasa', '@bdleonanda Ga bisa dipungkiri pasokan drone iran telah mengubah jalan perang di ukraina. Rusia bisa menghemat anggaran perangnya secara efektif.beda waktu pertama invasi rusia mengandalkan tank dan helicopter tempurnya.dan ternyata jadi sasaran empuk manpad dan atgm', 'ga bisa dipungkiri pasokan drone iran telah mengubah jalan perang di ukraina rusia bisa menghemat anggaran perangnya secara efektif beda waktu pertama invasi rusia mengandalkan tank dan helicopter tempurnya dan ternyata jadi sasaran empuk manpad dan atgm', 'umum', 'tidak', ''),
('1619548604888387592', '2023-01-29 04:10:51', 'gemukpack', '@bdleonanda Jauh hari sebelum invasi Rusia ke Ukrania bulan februari.\nVladimir putin dah kasih sinyal akan terjadinya perang nuklir.\nKerusakan hebat n kematian massal plus bumi dalam gelap gulita.\nHujan radioaktif deras hujam bumi baik dari udara, darat,lautan.\nKiamat super power.', 'jauh hari sebelum invasi rusia ke ukrania bulan februari vladimir putin dah kasih sinyal akan terjadinya perang nuklir kerusakan hebat n kematian massal plus bumi dalam gelap gulita hujan radioaktif deras hujam bumi baik dari udara darat lautan kiamat super power', 'umum', 'pakai', '{\'classified_text\': \'jauh [-2] hari sebelum invasi rusia ke ukrania bulan februari vladimir putin dah kasih sinyal akan terjadinya perang [-4] nuklir kerusakan [-4] hebat [3] n kematian [-3] massal plus bumi dalam gelap [-2] gulita hujan radioaktif deras hujam bumi baik [4] dari udara darat lautan kiamat super [4] power\', \'tweet_text\': \' jauh hari sebelum invasi rusia ke ukrania bulan februari vladimir putin dah kasih sinyal akan terjadinya perang nuklir kerusakan hebat n kematian massal plus bumi dalam gelap gulita hujan radioaktif deras hujam bumi baik dari udara darat lautan kiamat super power\', \'sentence_score\': [\'jauh [-2] hari sebelum invasi rusia ke ukrania bulan februari vladimir putin dah kasih sinyal akan terjadinya perang [-4] nuklir kerusakan [-4] hebat [3] n kematian [-3] massal plus bumi dalam gelap [-2] gulita hujan radioaktif deras hujam bumi baik [4] dari udara darat lautan kiamat super [4] power\'], \'max_positive\': 4, \'max_negative\': -4, \'kelas\': \'neutral\'}'),
('1619620232737456133', '2023-01-29 08:55:29', 'MightyWar3', 'Menurut Papperger, pada tahun 2022, Rheinmetall membuat masing masing sekitar 60.000 hingga 70.000 peluru tank dan peluru artileri, tetapi produksi dapat segera ditingkatkan. Permintaan amunisi ini melonjak di dunia sejak invasi Rusia ke Ukraina Februari lalu. (4)', 'menurut papperger pada tahun rheinmetall membuat masing masing sekitar hingga peluru tank dan peluru artileri tetapi produksi dapat segera ditingkatkan permintaan amunisi ini melonjak di dunia sejak invasi rusia ke ukraina februari lalu', 'umum', 'tidak', ''),
('1619626664581005312', '2023-01-29 09:21:02', 'H4T14K4LN4L42', '@bdleonanda Inggris jerman AS sudah tak mau kirim senjata ke Ukraina, karna slalu hilang di curi penjahat Ukraina di serahkan ke rusia yuk di modifikasi,.\nUkraina telah kalah Rothschild Rockefeller telah kalah. Swiss markasnya yg ancam membekukan asetnya di Swiss tggu giliran akan di invasi.', 'inggris jerman as sudah tak mau kirim senjata ke ukraina karna slalu hilang di curi penjahat ukraina di serahkan ke rusia yuk di modifikasi ukraina telah kalah rothschild rockefeller telah kalah swiss markasnya yg ancam membekukan asetnya di swiss tggu giliran akan di invasi', 'umum', 'tidak', ''),
