('1625313626860175361', '2023-02-14 01:59:00', 'golkarpedia', 'Bobby Rizaldi Tegaskan Golkar Dukung Perdamaian Di Ukraina Dan Kecam Invasi Rusia\n#airlanggahartarto #airlanggapemersatu #airlanggauntukindonesia #partaigolkar #golkarpedia #golkarsolid #AirlanggaPresiden\nhttps://t.co/TjNueN0WW3', 'bobby rizaldi tegaskan golkar dukung perdamaian di ukraina dan kecam invasi', 'umum', 'pakai', '{\'classified_text\': \'bobby rizaldi tegaskan golkar dukung [3] perdamaian [6] di ukraina dan kecam invasi\', \'tweet_text\': \' bobby rizaldi tegaskan golkar dukung perdamaian di ukraina dan kecam invasi\', \'sentence_score\': [\'bobby rizaldi tegaskan golkar dukung [3] perdamaian [6] di ukraina dan kecam invasi\'], \'max_positive\': 6, \'max_negative\': -1, \'kelas\': \'positive\'}'),
